    realtype AUX_VAR_syn_T_C1_PDL2_total = (_species_var[SP_syn_T_C1_PD1_PDL2] / _class_parameter[P_syn_T_C1]) + (_species_var[SP_syn_T_C1_PDL2] / _class_parameter[P_syn_T_C1]);

