    NV_DATA_S(_y)[SP_syn_T_C1_CD80] = _species_var[SP_syn_T_C1_CD80];
    // syn_T_C1.CD86 = (C1_CD86_total / A_cell) * syn_T_C1
    _species_var[SP_syn_T_C1_CD86] = (PARAM(P_C1_CD86_total) / PARAM(P_A_cell)) * PARAM(P_syn_T_C1);
    NV_DATA_S(_y)[SP_syn_T_C1_CD86] = _species_var[SP_syn_T_C1_CD86];
    // syn_T_APC.PD1 = (T_PD1_total / A_Tcell) * syn_T_APC
    _species_var[SP_syn_T_APC_PD1] = (PARAM(P_T_PD1_total) / PARAM(P_A_Tcell)) * PARAM(P_syn_T_APC);
