    NV_DATA_S(_y)[SP_syn_T_APC_CD28] = _species_var[SP_syn_T_APC_CD28];
    // syn_T_APC.CTLA4 = (T_CTLA4_syn / A_Tcell) * syn_T_APC
    _species_var[SP_syn_T_APC_CTLA4] = (PARAM(P_T_CTLA4_syn) / PARAM(P_A_Tcell)) * PARAM(P_syn_T_APC);
