    NV_DATA_S(_y)[SP_syn_T_APC_PDL1_total] = _species_var[SP_syn_T_APC_PDL1_total];
    realtype AUX_VAR_syn_T_APC_PDL2_total = (_species_var[SP_syn_T_APC_PD1_PDL2] / _class_parameter[P_syn_T_APC]) + (_species_var[SP_syn_T_APC_PDL2] / _class_parameter[P_syn_T_APC]);
