    realtype AUX_VAR_syn_T_C1_PDL1_total = (_species_var[SP_syn_T_C1_PDL1] / _class_parameter[P_syn_T_C1]) + (_species_var[SP_syn_T_C1_PD1_PDL1] / _class_parameter[P_syn_T_C1]) + (_species_var[SP_syn_T_C1_PDL1_aPDL1] / _class_parameter[P_syn_T_C1]) + 2.0 * (_species_var[SP_syn_T_C1_PDL1_aPDL1_PDL1] / _class_parameter[P_syn_T_C1]) + (_species_var[SP_syn_T_C1_PDL1_CD80] / _class_parameter[P_syn_T_C1]) + (_species_var[SP_syn_T_C1_PDL1_CD80_CD28] / _class_parameter[P_syn_T_C1]) + (_species_var[SP_syn_T_C1_PDL1_CD80_CTLA4] / _class_parameter[P_syn_T_C1]);
